def _q(subject, topic, difficulty, stem, options, correct, explanation, learning_point, reference):
    return {
        "subject": subject, "topic": topic, "difficulty": difficulty, "question_text": stem,
        "options": [
            {"letter": letter, "text": text, "is_correct": letter == correct}
            for letter, text in zip("ABCDE", options)
        ],
        "explanation": explanation, "learning_point": learning_point, "reference": reference,
    }


